class Variable:
    def __init__(self, value):
        self.value = np.array(value)
        self.grad = None

    def backward(self):
        raise NotImplementedError

class Constant(Variable):
    def backward(self):
        return None

class Add(Variable):
    def __init__(self, x, y):
        super().__init__(x.value + y.value)
        self.x = x
        self.y = y

    def backward(self):
        return self.x.grad + self.y.grad

class Mul(Variable):
    def __init__(self, x, y):
        super().__init__(x.value * y.value)
        self.x = x
        self.y = y

    def backward(self):
        return self.x.grad * self.y.value + self.y.grad * self.x.value

