public class BaseRepository<T> where T : class
{
    protected readonly DbContext _dbContext;
    protected readonly DbSet<T> _dbSet;

    public BaseRepository(DbContext dbContext)
    {
        _dbContext = dbContext;
        _dbSet = dbContext.Set<T>();
    }

    public virtual async Task<T> FindAsync(object id)
    {
        return await _dbSet.FindAsync(id);
    }

    public virtual async Task<T> FindAsync(Expression<Func<T, bool>> predicate)
    {
        return await _dbSet.FirstOrDefaultAsync(predicate);
    }

    public virtual async Task<T> FindAsync(Expression<Func<T, bool>> predicate, params Expression<Func<T, object>>[] includeProperties)
    {
        return await _dbSet
            .Include(includeProperties.Select(p => p.Body as MemberExpression).Select(m => m.Member.Name))
            .FirstOrDefaultAsync(predicate);
    }

    public virtual async Task<T> FindAsync(Expression<Func<T, bool>> predicate, params string[] includeProperties)
    {
        return await _dbSet
            .Include(includeProperties)
